            <div style={{flex:1}}>
              <div style={{fontSize:22,fontWeight:700,fontFamily:"'Poppins',sans-serif",color:'#fff'}}>SetToClose — Agencia</div>
              <div style={{fontSize:12,color:'#444',marginTop:2}}>{dateFrom} to {dateTo} · {offices.length} oficinas activas</div>
            </div>
